1	/** @import { ArrowFunctionExpression, BinaryOperator, ClassDeclaration, Expression, FunctionDeclaration, FunctionExpression, Identifier, ImportDeclaration, MemberExpression, LogicalOperator, Node, Pattern, UnaryOperator, VariableDeclarator, Super } from 'estree' */
2	/** @import { Context, Visitor } from 'zimmerframe' */
3	/** @import { AST, BindingKind, DeclarationKind } from '#compiler' */
4	import is_reference from 'is-reference';
5	import { walk } from 'zimmerframe';
6	import { create_expression_metadata } from './nodes.js';
7	import * as b from '#compiler/builders';
8	import * as e from '../errors.js';
9	import {
10		extract_identifiers,
11		extract_identifiers_from_destructuring,
12		object,
13		unwrap_pattern
14	} from '../utils/ast.js';
15	import { is_reserved, is_rune } from '../../utils.js';
16	import { determine_slot } from '../utils/slot.js';
17	import { validate_identifier_name } from './2-analyze/visitors/shared/utils.js';
18	
19	const UNKNOWN = Symbol('unknown');
20	/** Includes `BigInt` */
21	const NUMBER = Symbol('number');
22	const STRING = Symbol('string');
23	const FUNCTION = Symbol('string');
24	
25	/** @type {Record<string, [type: typeof NUMBER | typeof  STRING | typeof  UNKNOWN, fn?: Function]>} */
26	const globals = {
27		BigInt: [NUMBER],
28		'Math.min': [NUMBER, Math.min],
29		'Math.max': [NUMBER, Math.max],
30		'Math.random': [NUMBER],
31		'Math.floor': [NUMBER, Math.floor],
32		// @ts-ignore
33		'Math.f16round': [NUMBER, Math.f16round],
34		'Math.round': [NUMBER, Math.round],
35		'Math.abs': [NUMBER, Math.abs],
36		'Math.acos': [NUMBER, Math.acos],
37		'Math.asin': [NUMBER, Math.asin],
38		'Math.atan': [NUMBER, Math.atan],
39		'Math.atan2': [NUMBER, Math.atan2],
40		'Math.ceil': [NUMBER, Math.ceil],
41		'Math.cos': [NUMBER, Math.cos],
42		'Math.sin': [NUMBER, Math.sin],
43		'Math.tan': [NUMBER, Math.tan],
44		'Math.exp': [NUMBER, Math.exp],
45		'Math.log': [NUMBER, Math.log],
46		'Math.pow': [NUMBER, Math.pow],
47		'Math.sqrt': [NUMBER, Math.sqrt],
48		'Math.clz32': [NUMBER, Math.clz32],
49		'Math.imul': [NUMBER, Math.imul],
50		'Math.sign': [NUMBER, Math.sign],
51		'Math.log10': [NUMBER, Math.log10],
52		'Math.log2': [NUMBER, Math.log2],
53		'Math.log1p': [NUMBER, Math.log1p],
54		'Math.expm1': [NUMBER, Math.expm1],
55		'Math.cosh': [NUMBER, Math.cosh],
56		'Math.sinh': [NUMBER, Math.sinh],
57		'Math.tanh': [NUMBER, Math.tanh],
58		'Math.acosh': [NUMBER, Math.acosh],
59		'Math.asinh': [NUMBER, Math.asinh],
60		'Math.atanh': [NUMBER, Math.atanh],
61		'Math.trunc': [NUMBER, Math.trunc],
62		'Math.fround': [NUMBER, Math.fround],
63		'Math.cbrt': [NUMBER, Math.cbrt],
64		Number: [NUMBER, Number],
65		'Number.isInteger': [NUMBER, Number.isInteger],
66		'Number.isFinite': [NUMBER, Number.isFinite],
67		'Number.isNaN': [NUMBER, Number.isNaN],
68		'Number.isSafeInteger': [NUMBER, Number.isSafeInteger],
69		'Number.parseFloat': [NUMBER, Number.parseFloat],
70		'Number.parseInt': [NUMBER, Number.parseInt],
71		String: [STRING, String],
72		'String.fromCharCode': [STRING, String.fromCharCode],
73		'String.fromCodePoint': [STRING, String.fromCodePoint]
74	};
75	
76	/** @type {Record<string, any>} */
77	const global_constants = {
78		'Math.PI': Math.PI,
79		'Math.E': Math.E,
80		'Math.LN10': Math.LN10,
81		'Math.LN2': Math.LN2,
82		'Math.LOG10E': Math.LOG10E,
83		'Math.LOG2E': Math.LOG2E,
84		'Math.SQRT2': Math.SQRT2,
85		'Math.SQRT1_2': Math.SQRT1_2
86	};
